<span class="line"><span style="color:#D73A49;">if</span><span style="color:#24292E;"> (tools.</span><span style="color:#6F42C1;">aiHasData</span><span style="color:#24292E;">()) tools.</span><span style="color:#6F42C1;">aiCommitToLayer</span><span style="color:#24292E;">(</span><span style="color:#032F62;">&quot;layer1&quot;</span><span style="color:#24292E;">);</span></span>
